  const updateMasterDataState = async (newData: Record<string, ULPData>) => {
    setMasterData(newData);
    setIsSyncing(true);
    try {
      await api.updateMasterData(newData);
    } catch (e) {
      alert("Gagal menyimpan perubahan Master Data ke server.");
    } finally {
      setIsSyncing(false);
    }
  };

