  const handleLogin = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) {
      setView('DASHBOARD');
    } else if (selectedRole === UserRole.GUEST) {
      setView('TABLE');
    } else {
      setView('INPUT');
    }
  };

