            />
            <div className="absolute bottom-0 left-0 right-0 bg-black/50 backdrop-blur-sm p-3 text-center">
              <a 
                href={previewUrl} 
                target="_blank" 
                rel="noreferrer" 
                className="text-white text-sm font-bold bg-primary px-4 py-2 rounded-md hover:bg-cyan-600 transition-colors inline-block"
              >
                Buka di Tab Baru
              </a>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

import { ReportData, ULPData } from '../types';

// ==================================================================================
// ⚠️ PENTING: PASTIKAN URL DI BAWAH INI ADALAH URL "WEB APP" YANG SUDAH DI-DEPLOY
// Pastikan "Who has access" diatur ke "Anyone" di Google Apps Script.
// ==================================================================================
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbw4uVV-vGPeL0Peg-bdco6VL8zKAH8Z5N3ZBJo3bYEZt8IVHNkBAuKluLsQLlu7msQ/exec'; 

export const api = {
  // Ambil semua data (Laporan & Master Data)
  getAllData: async () => {
    try {
      if (!GOOGLE_SCRIPT_URL || GOOGLE_SCRIPT_URL.includes('MASUKKAN_URL')) {
          console.warn("URL Google Script belum diset dengan benar.");
          return null;
      }

      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors',
        headers: { 'Content-Type': 'application/json' }
      });

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.indexOf("application/json") !== -1) {
        return await response.json();
      } else {
        // Jika bukan JSON, kemungkinan besar ini adalah halaman HTML error/login Google
        const text = await response.text();
        console.error("Respon server bukan JSON. Kemungkinan deployment script salah atau izin akses tidak diset ke 'Anyone'.", text.substring(0, 200));
        throw new Error("Respon database tidak valid (Bukan JSON). Periksa deployment Google Script Anda.");
      }
    } catch (error) {
      console.error("Error fetching data:", error);
      throw error;
    }
  },

  // Simpan laporan baru
  saveReport: async (report: ReportData) => {
    try {
      const response = await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors', // Google Script POST sering kali membutuhkan no-cors jika tidak menghandle OPTIONS
        body: JSON.stringify({
          action: 'saveReport',
          data: report
        })
      });
      return true;
    } catch (error) {
      console.error("Error saving report:", error);
      throw error;
    }
  },

  // Update Master Data
  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({
          action: 'updateMaster',
          data: masterData
        })
      });
      return true;
    } catch (error) {
      console.error("Error updating master data:", error);
      throw error;
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
