  const handleLogout = () => {
    setRole(null);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setTableStartDate('');
    setTableEndDate('');
    setTableUlpFilter('');
    setView('LOGIN');
    setShowAdminLogin(false);
    setAdminPassword('');
  };

  const handleSaveReport = async (data: ReportData) => {
    setIsSyncing(true);
    try {
      await api.saveReport(data);
      // Optimistic update
      setReports(prev => [data, ...prev]);
      alert('Data Laporan berhasil dikirim ke Server!');
      setView('TABLE');
      // Refresh data setelah beberapa detik untuk memastikan spreadsheet sudah update
      setTimeout(() => fetchData(false), 3000);
