import { ReportData, ULPData } from '../types';

// ==================================================================================
// ⚠️ PENTING: PASTIKAN URL DI BAWAH INI ADALAH URL "WEB APP" YANG SUDAH DI-DEPLOY
// Langkah Perbaikan: 
// 1. Di Google Apps Script, Klik "Deploy" -> "Manage Deployments".
// 2. Edit deployment aktif, pastikan "Who has access" adalah "Anyone".
// 3. Salin URL Web App yang baru jika berubah.
// ==================================================================================
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbxd3fmKldbMeRHOY6kEbfUn93DFvIhf50AbwM_g7FJysbqoRYq46SHoO2v0Gb1ZaBmy/exec'; 

export const api = {
  // Ambil semua data (Laporan & Master Data)
  getAllData: async () => {
    try {
      if (!GOOGLE_SCRIPT_URL || GOOGLE_SCRIPT_URL.includes('MASUKKAN_URL')) {
          throw new Error("URL Database belum dikonfigurasi.");
      }

      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        throw new Error(`Server bermasalah (Status: ${response.status})`);
      }

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.indexOf("application/json") !== -1) {
        return await response.json();
      } else {
        // Jika respon berisi HTML (biasanya <DOCTYPE), ini adalah halaman error/login Google
        const text = await response.text();
        console.error("Respon server bukan JSON:", text.substring(0, 300));

        if (text.includes("<!DOCTYPE") || text.includes("<html")) {
           throw new Error("Izin Akses Ditolak: Pastikan Deployment Google Script diatur ke 'Anyone' (Siapa saja, bahkan tanpa akun Google).");
        }
        throw new Error("Database mengembalikan format yang salah.");
      }
    } catch (error: any) {
      console.error("Error fetching data:", error);
      throw error;
    }
  },

  // Simpan laporan baru
  saveReport: async (report: ReportData) => {
    try {
      // Kita gunakan POST untuk simpan data
      const response = await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors', // Penting untuk Google Apps Script agar tidak kena CORS preflight
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'saveReport',
          data: report
        })
      });
      // Karena no-cors, kita tidak bisa baca body respon, anggap sukses jika tidak throw
      return true;
    } catch (error) {
      console.error("Error saving report:", error);
      throw error;
    }
  },

  // Update Master Data
  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'updateMaster',
          data: masterData
        })
      });
      return true;
    } catch (error) {
      console.error("Error updating master data:", error);
      throw error;
    }
  }
};

