import { ReportData, ULPData } from '../types';

/**
 * ⚠️ PENTING: CARA MENDAPATKAN URL DATABASE (GOOGLE APPS SCRIPT)
 * 1. Di Google Apps Script, klik tombol "Deploy" -> "New Deployment".
 * 2. Pilih type "Web App".
 * 3. Description: "Yandal Patrol API".
 * 4. Execute as: "Me" (Email Anda).
 * 5. Who has access: "Anyone" (WAJIB PILIH INI).
 * 6. Klik "Deploy". Salin "Web App URL" dan tempel di bawah ini.
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbxd3fmKldbMeRHOY6kEbfUn93DFvIhf50AbwM_g7FJysbqoRYq46SHoO2v0Gb1ZaBmy/exec'; 

export const api = {
  getAllData: async () => {
    try {
      if (!GOOGLE_SCRIPT_URL || GOOGLE_SCRIPT_URL.includes('MASUKKAN_URL')) {
        throw new Error("URL Database belum dikonfigurasi.");
      }

      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        throw new Error(`Server bermasalah (Status: ${response.status})`);
      }

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.indexOf("application/json") !== -1) {
        return await response.json();
      } else {
        const text = await response.text();
        if (text.includes("<!DOCTYPE") || text.includes("<html")) {
          throw new Error("Izin Akses Ditolak (CORS): Pastikan Deployment Google Script diatur ke 'Anyone'.");
        }
        throw new Error("Database mengembalikan format non-JSON.");
      }
    } catch (error: any) {
      console.error("Fetch error details:", error);
      // Menangani error "Failed to fetch" secara spesifik
      if (error.name === 'TypeError' && error.message === 'Failed to fetch') {
        throw new Error("Koneksi Diblokir (Failed to Fetch). Ini biasanya karena URL salah atau Deployment Apps Script belum diset ke 'Anyone'.");
      }
      throw error;
    }
  },

  saveReport: async (report: ReportData) => {
    try {
      // POST ke GAS seringkali memerlukan mode no-cors jika server tidak menghandle OPTIONS
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'saveReport',
          data: report
        })
      });
      return true;
    } catch (error) {
      console.error("Error saving report:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'updateMaster',
          data: masterData
        })
      });
      return true;
    } catch (error) {
      console.error("Error updating master data:", error);
      throw error;
    }
  }
};

