const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [errorLoad, setErrorLoad] = useState<string | null>(null);
  const [loadingStatus, setLoadingStatus] = useState("Menghubungkan ke Database...");
  const [isSyncing, setIsSyncing] = useState(false);

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });

  const [tableStartDate, setTableStartDate] = useState('');
  const [tableEndDate, setTableEndDate] = useState('');
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);

  const fetchData = async (showLoading = true) => {
    if (showLoading) {
      setIsLoading(true);
      setErrorLoad(null);
      setLoadingStatus("Sinkronisasi data...");
    }
    try {
      const data = await api.getAllData();
      if (data) {
        if (data.reports && Array.isArray(data.reports)) {
          const sortedReports = data.reports.sort((a: ReportData, b: ReportData) => 
            new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
          );
          setReports(sortedReports);
        }
        if (data.masterData && Object.keys(data.masterData).length > 0) {
          setMasterData(data.masterData);
        }
      } else {
        setReports([]);
      }
    } catch (error: any) {
      console.error("App catch error:", error);
      setErrorLoad(error.message || "Gagal terhubung ke database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData(true);
  }, []);

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setSession({ ulp: null, petugas1: null, petugas2: null }); 
      setView('DASHBOARD');
      setAdminPassword('');
      setLoginError('');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    if (role === UserRole.GUEST) {
      setView('TABLE');
    } else {
      setView('INPUT');
    }
  };

  const handleLogout = () => {
    setRole(null);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setTableStartDate('');
    setTableEndDate('');
    setTableUlpFilter('');
    setView('LOGIN');
    setShowAdminLogin(false);
    setAdminPassword('');
  };

  const handleSaveReport = async (data: ReportData) => {
    setIsSyncing(true);
    try {
      await api.saveReport(data);
      // Optimistic update
      setReports(prev => [data, ...prev]);
      alert('Data Laporan berhasil dikirim ke Server!');
      setView('TABLE');
      // Refresh data setelah beberapa detik
      setTimeout(() => fetchData(false), 3000);
    } catch (e) {
      alert("Gagal menyimpan. Cek koneksi internet Anda.");
    } finally {
      setIsSyncing(false);
    }
  };

  const filteredReportsForTable = useMemo(() => {
    return reports.filter(r => {
      const sessionMatch = !session.ulp || r.ulp === session.ulp;
      if (!sessionMatch) return false;

      const adminUlpMatch = role !== UserRole.ADMIN || !tableUlpFilter || r.ulp === tableUlpFilter;
      if (!adminUlpMatch) return false;

      const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
      const startMatch = !tableStartDate || reportDate >= tableStartDate;
      const endMatch = !tableEndDate || reportDate <= tableEndDate;

      return startMatch && endMatch;
    });
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  const dashboardReports = reports.filter(r => !session.ulp || r.ulp === session.ulp);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4 p-4 text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-medium text-lg animate-pulse">{loadingStatus}</p>
      </div>
    );
  }

  if (errorLoad) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 p-6">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-lg w-full border border-red-100 animate-fade-in">
          <div className="bg-red-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-10 h-10 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 text-center mb-2">Gagal Terhubung</h2>
          <div className="bg-red-50 p-4 rounded-xl border border-red-100 mb-8">
            <p className="text-red-700 text-sm leading-relaxed font-semibold text-center">{errorLoad}</p>
          </div>

          <div className="space-y-4">
            <button 
              onClick={() => fetchData(true)}
              className="w-full bg-primary text-white px-6 py-4 rounded-2xl font-bold hover:bg-cyan-800 transition-all shadow-lg shadow-cyan-100 flex items-center justify-center gap-2"
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
              Coba Lagi
            </button>

            <div className="p-5 bg-slate-50 rounded-2xl text-[11px] text-slate-600 border border-slate-200">
              <p className="font-extrabold text-slate-800 mb-2 uppercase tracking-wider flex items-center gap-2">
                <span className="w-2 h-2 bg-primary rounded-full"></span> 
                Cara Memperbaiki (Sisi Google):
              </p>
              <ol className="list-decimal list-inside space-y-2 font-medium">
                <li>Buka Editor <b>Google Apps Script</b> Anda.</li>
                <li>Klik tombol <b>Deploy</b> (Biru) &gt; <b>Manage Deployments</b>.</li>
                <li>Klik ikon <b>Pensil (Edit)</b> pada deployment terbaru.</li>
                <li>Ubah <i>"Who has access"</i> menjadi <b className="text-red-600">"Anyone"</b>.</li>
                <li>Klik <b>Deploy</b>. Pastikan URL di file <i>api.ts</i> sudah sesuai.</li>
              </ol>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-1">PLN Electricity Services</h2>
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase tracking-tight">Unit Layanan Bukittinggi</h1>

            <div className="relative group mb-6">
              <img src={APP_LOGO} alt="Logo App" className="relative h-48 mx-auto object-contain transition-transform duration-500 hover:scale-110" />
            </div>
            <h2 className="text-2xl font-bold text-primary mb-1">Aplikasi Monitoring</h2>
            <h2 className="text-2xl font-bold text-primary mb-2">Yandal Patrol</h2>
          </div>

          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-semibold py-3 px-6 rounded-lg transition-all transform hover:scale-[1.02] flex items-center justify-center gap-2 shadow-md">
              Login sebagai Petugas
            </button>

            {!showAdminLogin ? (
              <>
                <button onClick={() => setShowAdminLogin(true)} className="w-full bg-slate-800 hover:bg-slate-900 text-white font-semibold py-3 px-6 rounded-lg transition-all transform hover:scale-[1.02] flex items-center justify-center gap-2">
                  Login sebagai Admin
                </button>
                <button onClick={() => handleInitialRoleSelect(UserRole.GUEST)} className="w-full bg-white border-2 border-slate-200 hover:border-primary hover:text-primary text-slate-600 font-semibold py-3 px-6 rounded-lg transition-all transform hover:scale-[1.02] flex items-center justify-center gap-2">
                  Tampilkan Data
                </button>
                <button onClick={() => setView('ABOUT')} className="w-full text-slate-400 hover:text-primary text-xs font-semibold py-2 transition-colors uppercase mt-4">
                  Tentang Aplikasi
                </button>
              </>
            ) : (
              <form onSubmit={handleAdminLoginSubmit} className="bg-slate-50 p-4 rounded-lg border border-slate-200 animate-fade-in">
                <h3 className="text-sm font-semibold text-slate-700 mb-2">Verifikasi Admin</h3>
                <input 
                  type="password"
                  autoFocus
                  className={`w-full px-4 py-2 border rounded-lg mb-2 outline-none ${loginError ? 'border-red-500 bg-red-50' : 'border-slate-300'}`}
                  value={adminPassword}
                  onChange={(e) => { setAdminPassword(e.target.value); setLoginError(''); }}
                  placeholder="Password Admin..."
                />
                {loginError && <p className="text-xs text-red-500 mb-3 font-medium">{loginError}</p>}
                <div className="flex gap-2">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-2 text-sm text-slate-600 bg-white border border-slate-300 rounded-lg">Batal</button>
                  <button type="submit" className="flex-1 py-2 text-sm font-bold bg-slate-800 text-white rounded-lg">Masuk</button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CONFIG' && role) {
    return (
      <LoginConfig 
        role={role} 
        masterData={masterData} 
        appLogo={APP_LOGO}
        onBack={() => setView('LOGIN')}
        onConfirm={handleConfigConfirm}
      />
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {isSyncing && (
        <div className="fixed top-4 right-4 z-50 bg-white shadow-lg rounded-full px-4 py-2 flex items-center gap-2 border border-slate-200">
          <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
          <span className="text-xs font-medium text-slate-600">Sinkronisasi...</span>
        </div>
      )}

      <header className="bg-white shadow-sm z-20 sticky top-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
            <div className="flex items-center gap-4">
               <img src={LOGO_URL} alt="PLN" className="h-8 object-contain cursor-pointer" onClick={() => setView('LOGIN')} />
               <div className="w-px h-8 bg-slate-200 hidden sm:block"></div>
               <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('ABOUT')}>
                 <img src={APP_LOGO} alt="App" className="h-8 object-contain" />
                 <div className="flex flex-col leading-none">
                   <span className="font-bold text-sm text-slate-800">Yandal Patrol</span>
                   <span className="text-[9px] text-primary font-bold uppercase">{session.ulp || 'Unit Bukittinggi'}</span>
                 </div>
               </div>
            </div>
            <button onClick={handleLogout} className="text-sm text-red-600 font-medium px-3 py-1 rounded-md hover:bg-red-50 transition-colors">Logout</button>
        </div>

        <div className="max-w-7xl mx-auto px-4">
          <nav className="-mb-px flex space-x-8 overflow-x-auto no-scrollbar">
            {role === UserRole.ADMIN && (
              <>
                <button onClick={() => setView('DASHBOARD')} className={`pb-4 px-1 border-b-2 font-medium text-sm whitespace-nowrap ${view === 'DASHBOARD' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}>Dashboard</button>
                <button onClick={() => setView('REKAP')} className={`pb-4 px-1 border-b-2 font-medium text-sm whitespace-nowrap ${view === 'REKAP' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}>Rekap Petugas</button>
                <button onClick={() => setView('SETTINGS')} className={`pb-4 px-1 border-b-2 font-medium text-sm whitespace-nowrap ${view === 'SETTINGS' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}>Kelola Data</button>
              </>
            )}
            {role !== UserRole.GUEST && (
              <button onClick={() => setView('INPUT')} className={`pb-4 px-1 border-b-2 font-medium text-sm whitespace-nowrap ${view === 'INPUT' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}>Input Data</button>
            )}
            <button onClick={() => setView('TABLE')} className={`pb-4 px-1 border-b-2 font-medium text-sm whitespace-nowrap ${view === 'TABLE' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}>Data Laporan</button>
            <button onClick={() => setView('ABOUT')} className={`pb-4 px-1 border-b-2 font-medium text-sm whitespace-nowrap ${view === 'ABOUT' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}>Tentang</button>
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 py-8">
        {view === 'DASHBOARD' && <Dashboard reports={dashboardReports} />}
        {view === 'REKAP' && role === UserRole.ADMIN && <AdminRekap reports={reports} masterData={masterData} />}
        {view === 'SETTINGS' && role === UserRole.ADMIN && (
          <AdminSettings 
            masterData={masterData}
            onAddPetugas={(ulp, names) => { 
              const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: [...masterData[ulp].petugas, ...names]}};
              setMasterData(nd); api.updateMasterData(nd); 
            }}
            onDeletePetugas={(ulp, n) => {
              const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: masterData[ulp].petugas.filter(p => p !== n)}};
              setMasterData(nd); api.updateMasterData(nd);
            }}
            onAddPenyulang={(ulp, names) => {
              const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: [...masterData[ulp].penyulang, ...names]}};
              setMasterData(nd); api.updateMasterData(nd);
            }}
            onDeletePenyulang={(ulp, n) => {
              const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: masterData[ulp].penyulang.filter(p => p !== n)}};
              setMasterData(nd); api.updateMasterData(nd);
            }}
          />
        )}
        {view === 'INPUT' && role !== UserRole.GUEST && (
          <InputForm 
            onSubmit={handleSaveReport}
            onCancel={() => setView('TABLE')}
            masterData={masterData}
            sessionData={session}
          />
        )}
        {view === 'TABLE' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Daftar Laporan Penugasan</h2>
                {session.ulp && <p className="text-sm text-slate-500">Menampilkan data untuk unit: <b>{session.ulp}</b></p>}
              </div>
              <div className="flex gap-2">
                 <button onClick={() => fetchData(true)} className="bg-slate-200 text-slate-700 px-4 py-2 rounded-lg font-bold hover:bg-slate-300 transition-colors flex items-center gap-2">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                    Refresh
                 </button>
                 {role !== UserRole.GUEST && (
                    <button onClick={() => setView('INPUT')} className="bg-primary text-white px-4 py-2 rounded-lg font-bold shadow-md hover:bg-cyan-800 transition-colors">Tambah Laporan</button>
                 )}
              </div>
            </div>

            <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-4 gap-4 animate-fade-in">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Dari Tanggal</label>
                <input type="date" className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm outline-none focus:ring-2 focus:ring-primary/20" value={tableStartDate} onChange={(e) => setTableStartDate(e.target.value)} />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Sampai Tanggal</label>
                <input type="date" className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm outline-none focus:ring-2 focus:ring-primary/20" value={tableEndDate} onChange={(e) => setTableEndDate(e.target.value)} />
              </div>
              {role === UserRole.ADMIN && (
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Filter ULP</label>
                  <select className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm bg-white outline-none focus:ring-2 focus:ring-primary/20" value={tableUlpFilter} onChange={(e) => setTableUlpFilter(e.target.value as ULPName)}>
                    <option value="">Semua ULP</option>
                    {Object.values(ULPName).map(u => <option key={u} value={u}>{u}</option>)}
                  </select>
                </div>
              )}
              <div className={`flex items-end ${role !== UserRole.ADMIN ? 'md:col-span-2' : ''}`}>
                <button onClick={() => { setTableStartDate(''); setTableEndDate(''); setTableUlpFilter(''); }} className="w-full py-2 px-4 bg-slate-100 hover:bg-slate-200 text-slate-600 font-semibold rounded-md text-sm border border-slate-200 transition-colors">
                  Reset Filter
                </button>
              </div>
            </div>

            <DataTable reports={filteredReportsForTable} />
          </div>
        )}
        {view === 'ABOUT' && (
          <div className="max-w-3xl mx-auto animate-fade-in">
            <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">
               <div className="bg-gradient-to-br from-primary to-cyan-800 p-8 text-white text-center">
                  <div className="flex justify-center mb-6">
                    <div className="bg-white p-4 rounded-2xl shadow-lg w-40 h-40 flex items-center justify-center">
                      <img src={APP_LOGO} alt="App" className="h-32 w-auto object-contain" />
                    </div>
                  </div>
                  <h1 className="text-3xl font-extrabold mb-2">Monitoring Yandal Patrol</h1>
                  <p className="text-cyan-100 font-medium">Monitoring Digital Pelaksanaan Pekerjaan Yandal</p>
               </div>
               <div className="p-8 md:p-12 space-y-10">
                  <section className="space-y-4">
                    <h2 className="text-xl font-bold text-primary flex items-center gap-2">
                       <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                       Keterangan Aplikasi
                    </h2>
                    <p className="text-slate-600 leading-relaxed text-lg italic">"Aplikasi ini untuk memonitoring Pelaksanaan Pekerjaan Yandal Patrol dari Petugas Yandal PLN Electricity Services Bukittinggi"</p>
                  </section>
                  <section className="space-y-4 border-t border-slate-100 pt-8">
                    <h2 className="text-xl font-bold text-primary flex items-center gap-2">
                       <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
                       Informasi Unit
                    </h2>
                    <div className="space-y-1">
                      <p className="text-slate-800 font-extrabold text-lg uppercase">PLN ELECTRICITY SERVICES UNIT LAYANAN BUKITTINGGI</p>
                      <p className="text-slate-600">Jl. Adinegoro No. 6, Tangah Jua Bukittinggi, Sumatera Barat</p>
                    </div>
                  </section>
                  <footer className="text-center pt-10 border-t border-slate-100 text-slate-400 text-sm">© Desember 2025, IT Unit Layanan Bukittinggi</footer>
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ReportData } from '../types';

interface DataTableProps {
  reports: ReportData[];
}

export const DataTable: React.FC<DataTableProps> = ({ reports }) => {
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  if (reports.length === 0) {
    return (
      <div className="bg-white p-12 text-center rounded-3xl shadow-sm border border-slate-200">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mx-auto text-slate-300 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
        </svg>
        <p className="text-slate-500 font-bold">Belum ada data laporan.</p>
        <p className="text-slate-400 text-xs mt-1 font-medium">Data mungkin masih disinkronkan atau tidak ditemukan.</p>
      </div>
    );
  }

  // Helper untuk mengecek validitas gambar
  const isValidImage = (str: any): boolean => {
    if (!str || typeof str !== 'string' || str.length < 10) return false;
    return str.startsWith('http') || str.startsWith('data:image');
  };

  const PhotoThumbnail = ({ url, label, type }: { url: string, label: string, type: 'sebelum' | 'sesudah' }) => (
    <div 
      className="group relative flex flex-col items-center gap-1 cursor-pointer" 
      onClick={() => setPreviewUrl(url)}
    >
      <div className={`w-14 h-14 rounded-xl border-2 overflow-hidden transition-all hover:scale-110 shadow-sm ${
        type === 'sebelum' ? 'border-amber-200 bg-amber-50' : 'border-green-200 bg-green-50'
      }`}>
        <img 
            src={url} 
            alt={label} 
            className="w-full h-full object-cover" 
            loading="lazy"
            onError={(e) => {
                (e.target as HTMLImageElement).src = "https://via.placeholder.com/150?text=Error";
            }} 
        />
      </div>
      <span className={`text-[8px] font-extrabold uppercase tracking-tighter ${
        type === 'sebelum' ? 'text-amber-600' : 'text-green-600'
      }`}>
        {label}
      </span>

      <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-slate-900 text-white text-[10px] rounded-lg opacity-0 group-hover:opacity-100 pointer-events-none transition-all whitespace-nowrap z-20 shadow-xl border border-white/20">
        Buka Foto
      </div>
    </div>
  );

  return (
    <>
      <div className="bg-white rounded-3xl shadow-md border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left text-slate-600">
            <thead className="text-xs text-slate-700 uppercase bg-slate-50/50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-5 font-extrabold">Waktu</th>
                <th className="px-6 py-5 font-extrabold">Penugasan</th>
                <th className="px-6 py-5 font-extrabold">Petugas</th>
                <th className="px-6 py-5 font-extrabold">Lokasi</th>
                <th className="px-6 py-5 font-extrabold text-center">Dokumentasi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {reports.map((report) => (
                <tr key={report.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-6 whitespace-nowrap align-top">
