/**
 * ⚠️ PENTING: PENGATURAN GOOGLE APPS SCRIPT
 * Pastikan saat Deploy:
 * 1. Execute as: "Me"
 * 2. Who has access: "Anyone" (WAJIB)
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbxd3fmKldbMeRHOY6kEbfUn93DFvIhf50AbwM_g7FJysbqoRYq46SHoO2v0Gb1ZaBmy/exec'; 

export const api = {
  getAllData: async () => {
    try {
      if (!GOOGLE_SCRIPT_URL || GOOGLE_SCRIPT_URL.includes('AKfycbxd3fmKldbMeRHOY6kEbfUn93DFvIhf50AbwM_g7FJysbqoRYq46SHoO2v0Gb1ZaBmy')) {
        // Jika ini masih URL default dan gagal, kita akan ditangani oleh App.tsx untuk masuk mode demo
      }

      // Gunakan URL sederhana untuk menghindari preflight CORS yang ketat
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors'
        // Menghapus custom headers agar request dianggap "Simple Request" oleh browser
      });

      if (!response.ok) {
        throw new Error(`Server bermasalah (Status: ${response.status})`);
      }

      const text = await response.text();
      try {
        return JSON.parse(text);
      } catch (e) {
        if (text.includes("<!DOCTYPE") || text.includes("<html")) {
          throw new Error("Izin Akses Ditolak: Pastikan Deployment Google Script diatur ke 'Anyone'.");
        }
        throw new Error("Format database tidak valid.");
      }
    } catch (error: any) {
      console.error("API Error:", error);
      throw error;
    }
  },

  saveReport: async (report: ReportData) => {
    try {
      // POST ke Google Apps Script paling aman menggunakan mode no-cors
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({
          action: 'saveReport',
          data: report
        })
      });
      return true;
    } catch (error) {
      console.error("Error saving report:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({
          action: 'updateMaster',
          data: masterData
        })
      });
      return true;
    } catch (error) {
      console.error("Error updating master data:", error);
      throw error;
    }
  }
};

