export const DataTable: React.FC<DataTableProps> = ({ reports }) => {
  const [previewImage, setPreviewImage] = useState<{ url: string } | null>(null);

  if (reports.length === 0) {
    return (
      <div className="bg-white p-12 text-center rounded-[2rem] shadow-sm border border-slate-200">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mx-auto text-slate-200 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
        </svg>
        <p className="text-slate-500 font-black uppercase tracking-widest text-sm">Belum ada data laporan.</p>
        <p className="text-slate-400 text-[10px] mt-2 font-bold uppercase tracking-tighter">Silahkan tambahkan laporan baru atau hubungkan ke database.</p>
      </div>
    );
  }

  /**
   * Mengatasi masalah "Karakter Ilegal":
   * Karakter '+' pada Base64 sering diubah menjadi spasi ' ' oleh server/database.
   * Fungsi ini mengembalikan spasi tersebut menjadi '+'.
   */
  const fixBase64 = (url: any): string => {
    if (typeof url !== 'string') return "";
    let clean = url.trim();
    if (clean.startsWith('data:image')) {
      const parts = clean.split(',');
      if (parts.length > 1) {
        // Hanya ganti spasi di bagian data (setelah koma)
        return parts[0] + ',' + parts[1].replace(/\s/g, '+');
      }
    }
    return clean;
  };

  const isValidImage = (str: any): boolean => {
    if (!str || typeof str !== 'string' || str.length < 50) return false;
    return str.trim().startsWith('data:image');
  };

  const PhotoCard = ({ url, label, type }: { url: string; label: string; type: 'sebelum' | 'sesudah' }) => {
    const cleanUrl = fixBase64(url);

    return (
      <div 
        className="group relative flex flex-col items-center gap-1 cursor-pointer" 
        onClick={() => setPreviewImage({ url: cleanUrl })}
      >
        <div className={`w-10 h-10 rounded-lg border-2 overflow-hidden transition-all duration-300 group-hover:scale-110 shadow-sm ${
          type === 'sebelum' ? 'border-amber-200 bg-amber-50' : 'border-cyan-200 bg-cyan-50'
        }`}>
          <img 
              src={cleanUrl} 
              alt={label} 
              className="w-full h-full object-cover" 
              loading="lazy"
              onError={(e) => {
                  (e.target as HTMLImageElement).src = "https://via.placeholder.com/80x80?text=ERR";
              }} 
          />
        </div>
        <span className={`text-[6px] font-black uppercase tracking-tighter leading-none ${
          type === 'sebelum' ? 'text-amber-600' : 'text-cyan-600'
        }`}>
          {label}
        </span>
      </div>
    );
  };

  return (
    <>
      <div className="bg-white rounded-[2rem] shadow-xl border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left text-slate-600">
            <thead className="text-[10px] text-slate-400 uppercase tracking-[0.2em] bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-8 py-6 font-black">Timeline</th>
                <th className="px-6 py-6 font-black">Assignment</th>
                <th className="px-6 py-6 font-black">Officer / Area</th>
                <th className="px-6 py-6 font-black">Location Detail</th>
                <th className="px-8 py-6 font-black text-center">Documentation</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {reports.map((report) => {
                const validSebelum = report.photos.sebelum.filter(isValidImage);
                const validSesudah = report.photos.sesudah.filter(isValidImage);

                return (
                  <tr key={report.id} className="hover:bg-slate-50/50 transition-all duration-300">
                    <td className="px-8 py-8 whitespace-nowrap align-top">
                      <div className="font-black text-slate-800 text-base tracking-tighter">{new Date(report.timestamp).toLocaleDateString('id-ID', { day: '2-digit', month: 'short', year: 'numeric' })}</div>
                      <div className="text-[10px] font-black text-primary mt-1 tracking-widest uppercase opacity-60">{new Date(report.timestamp).toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })} WIB</div>
                      <div className="mt-4 inline-flex items-center px-3 py-1 rounded-full text-[9px] font-black bg-slate-100 text-slate-500 uppercase tracking-widest">
                        {report.bulan}
                      </div>
