GANTI SELURUH fungsi handleDownloadExcel dengan :
const handleDownloadExcel = async () => {
  if (!window.ExcelJS) {
    alert("Library Excel belum dimuat. Silahkan refresh halaman.");
    return;
  }

  const workbook = new window.ExcelJS.Workbook();
  const worksheet = workbook.addWorksheet('Laporan Patrol');

  // ===============================
  // DEFINE COLUMNS
  // ===============================
  const columns: any[] = [
    { header: 'No', key: 'no', width: 5 },
    { header: 'Tanggal', key: 'tanggal', width: 15 },
    { header: 'No. Penugasan', key: 'noPenugasan', width: 20 },
    { header: 'ULP', key: 'ulp', width: 20 },
    { header: 'Petugas 1', key: 'petugas1', width: 20 },
    { header: 'Petugas 2', key: 'petugas2', width: 20 },
    { header: 'Penyulang', key: 'penyulang', width: 15 },
    { header: 'Keypoint', key: 'keypoint', width: 20 },
    { header: 'Start', key: 'start', width: 20 },
    { header: 'Finish', key: 'finish', width: 20 },
  ];

  for (let i = 1; i <= 6; i++) {
    columns.push({ header: `Foto Sebelum ${i}`, key: `sebelum_${i}`, width: 18 });
    columns.push({ header: `Foto Sesudah ${i}`, key: `sesudah_${i}`, width: 18 });
  }

  worksheet.columns = columns;

  worksheet.getRow(1).font = { bold: true };
  worksheet.getRow(1).alignment = { vertical: 'middle', horizontal: 'center' };

  // ===============================
  // HELPERS
  // ===============================
  const fixBase64 = (str: string) => {
    if (!str || !str.includes(',')) return null;
    const [meta, data] = str.split(',');
    return meta + ',' + data.replace(/\s/g, '+');
  };

  const getImageExtension = (b64: string): 'jpeg' | 'png' => {
    if (b64.startsWith('data:image/png')) return 'png';
    return 'jpeg';
  };

  // ===============================
  // ADD DATA + IMAGES
  // ===============================
  filteredReportsForTable.forEach((r, i) => {
    const rowIndex = i + 2;

    const row = worksheet.addRow({
      no: i + 1,
      tanggal: new Date(r.timestamp).toLocaleDateString('id-ID'),
      noPenugasan: r.noPenugasan,
      ulp: r.ulp,
      petugas1: r.petugas1,
      petugas2: r.petugas2,
      penyulang: r.penyulang,
      keypoint: r.keypoint,
      start: r.titikStart,
      finish: r.titikFinish,
    });

    row.height = 85;
    row.alignment = { vertical: 'middle', horizontal: 'center' };
    row.commit(); // 🔥 WAJIB sebelum addImage

    for (let s = 0; s < 6; s++) {
      const fotoSebelum = r.photos?.sebelum?.[s];
      const fotoSesudah = r.photos?.sesudah?.[s];

      // 🔥 ExcelJS pakai 0-based index
      const colSebelum = 9 + s * 2;
      const colSesudah = 10 + s * 2;

      if (fotoSebelum?.startsWith('data:image')) {
        const clean = fixBase64(fotoSebelum);
        if (clean) {
          const imageId = workbook.addImage({
            base64: clean,
            extension: getImageExtension(clean),
          });

          worksheet.addImage(imageId, {
            tl: { col: colSebelum, row: rowIndex - 1 },
            ext: { width: 110, height: 80 },
          });
        }
      }

      if (fotoSesudah?.startsWith('data:image')) {
        const clean = fixBase64(fotoSesudah);
        if (clean) {
          const imageId = workbook.addImage({
            base64: clean,
            extension: getImageExtension(clean),
          });

          worksheet.addImage(imageId, {
            tl: { col: colSesudah, row: rowIndex - 1 },
            ext: { width: 110, height: 80 },
          });
        }
      }
    }
  });

  // ===============================
  // DOWNLOAD
  // ===============================
  const dateStr = new Date().toISOString().split('T')[0];
  const filename = `Laporan_Patrol_${tableUlpFilter || 'Semua_ULP'}_${dateStr}.xlsx`;

  const buffer = await workbook.xlsx.writeBuffer();
  const blob = new Blob([buffer], {
    type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  });

  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  window.URL.revokeObjectURL(url);
};

