            <p className="text-red-700 text-xs font-bold leading-relaxed">{errorLoad}</p>
          </div>

          <div className="space-y-3">
            <button 
              onClick={() => fetchData(true)}
              className="w-full bg-primary text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-cyan-800 transition-all shadow-lg shadow-cyan-100"
            >
              Coba Sinkron Ulang
            </button>
            <button 
              onClick={startDemoMode}
              className="w-full bg-slate-100 text-slate-700 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all border border-slate-200"
            >
              Gunakan Mode Demo (Offline)
            </button>
          </div>

          <div className="mt-8 text-left bg-slate-50 p-5 rounded-2xl border border-slate-200">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Langkah Perbaikan Technical:</p>
            <ol className="list-decimal list-inside space-y-2 text-[11px] text-slate-600 font-bold">
              <li>Buka file <b>Google Apps Script</b> Anda.</li>
              <li>Pilih menu <b>Deploy</b> &gt; <b>Manage Deployments</b>.</li>
              <li>Klik ikon Pensil (Edit), pastikan "Who has access" adalah <span className="text-red-600">"Anyone"</span>.</li>
              <li>Klik <b>Deploy</b>. Pastikan URL di <i>services/api.ts</i> sudah benar.</li>
            </ol>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          {isDemoMode && (
            <div className="mb-4 bg-amber-50 text-amber-700 p-2 rounded-lg text-[10px] font-black text-center border border-amber-200 uppercase tracking-widest animate-pulse">
