/**
 * ⚠️ PENTING: PENGATURAN GOOGLE APPS SCRIPT
 * Pastikan fungsi doPost(e) di GAS Anda menangani action 'updateReport'.
 * Script harus mencari baris dengan ID yang sama di kolom ID dan menimpanya.
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbw4uVV-vGPeL0Peg-bdco6VL8zKAH8Z5N3ZBJo3bYEZt8IVHNkBAuKluLsQLlu7msQ/exec'; 

export const api = {
  getAllData: async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }

      const text = await response.text();

      if (text.trim().startsWith('<')) {
        console.error("Database mengembalikan HTML alih-alih JSON. Cek izin 'Anyone' di Google Script.");
        throw new Error("Izin Akses Ditolak: Pastikan Deployment Google Script diatur ke 'Anyone'.");
      }

      try {
        return JSON.parse(text);
      } catch (e) {
        throw new Error("Gagal mengolah data dari server (JSON parse error).");
      }
    } catch (error: any) {
      console.error("API Error:", error);
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      // Mengirimkan action yang berbeda jika sedang dalam mode edit
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: isEdit ? 'updateReport' : 'saveReport',
          data: report
        })
      });
      return true;
    } catch (error) {
      console.error("Error saving/updating report:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'updateMaster',
          data: masterData
        })
      });
      return true;
    } catch (error) {
      console.error("Error updating master data:", error);
      throw error;
    }
  }
};

