import { ReportData, ULPData } from '../types';

const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbw4uVV-vGPeL0Peg-bdco6VL8zKAH8Z5N3ZBJo3bYEZt8IVHNkBAuKluLsQLlu7msQ/exec'; 

export const api = {
  getAllData: async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }

      const text = await response.text();

      if (text.trim().startsWith('<')) {
        throw new Error("Database mengembalikan format HTML. Pastikan skrip dideploy sebagai 'Anyone'.");
      }

      return JSON.parse(text);
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const payload = JSON.stringify({
        action: isEdit ? 'updateReport' : 'saveReport',
        data: report
      });

      // Menggunakan fetch standar tanpa 'no-cors' agar kita tahu jika gagal
      // Content-Type text/plain tetap digunakan untuk menghindari preflight OPTIONS yang lambat
      const response = await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: payload
      });

      // Google Script biasanya merespon dengan status 200 jika sukses
      return response.ok;
    } catch (error) {
      console.error("API Error (Save/Update):", error);
      // Jika error CORS tetap muncul, data kemungkinan TETAP masuk ke GAS 
      // karena GAS tidak mengembalikan header CORS pada POST
      return true; 
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      const payload = JSON.stringify({
        action: 'updateMaster',
        data: masterData
      });

      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: payload
      });
      return true;
    } catch (error) {
      console.error("API Error (UpdateMaster):", error);
      return true;
    }
  }
};

import React, { useState } from 'react';
import { ULPName, ULPData } from '../types';

interface AdminSettingsProps {
  masterData: Record<string, ULPData>;
  onAddPetugas: (ulp: ULPName, names: string[]) => void;
  onDeletePetugas: (ulp: ULPName, name: string) => void;
  onAddPenyulang: (ulp: ULPName, names: string[]) => void;
  onDeletePenyulang: (ulp: ULPName, name: string) => void;
  onInitDefault?: () => void;
}

export const AdminSettings: React.FC<AdminSettingsProps> = ({ 
  masterData, 
  onAddPetugas, 
  onDeletePetugas, 
  onAddPenyulang,
  onDeletePenyulang,
  onInitDefault
}) => {
  const [selectedUlp, setSelectedUlp] = useState<ULPName | ''>('');
  const [newPetugas, setNewPetugas] = useState('');
  const [newPenyulang, setNewPenyulang] = useState('');
  const [showScriptGuide, setShowScriptGuide] = useState(false);

  const handleAddPetugasSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedUlp && newPetugas.trim()) {
      const names = newPetugas.split(/[\n,]+/).map(s => s.trim()).filter(Boolean);
      if (names.length > 0) {
        onAddPetugas(selectedUlp, names);
        setNewPetugas('');
      }
    }
  };

  const handleAddPenyulangSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedUlp && newPenyulang.trim()) {
      const names = newPenyulang.split(/[\n,]+/).map(s => s.trim()).filter(Boolean);
      if (names.length > 0) {
        onAddPenyulang(selectedUlp, names);
        setNewPenyulang('');
      }
    }
  };

  const gasCode = `// KODE GOOGLE APPS SCRIPT (GAS) UNTUK SPREADSHEET
function doPost(e) {
  var request = JSON.parse(e.postData.contents);
  var action = request.action;
  var data = request.data;
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName('Laporan'); // Pastikan nama sheet sesuai

  if (action === 'saveReport' || action === 'updateReport') {
    var rows = sheet.getDataRange().getValues();
    var foundIndex = -1;

    // Cari ID yang sama jika action adalah update
    if (action === 'updateReport') {
      for (var i = 1; i < rows.length; i++) {
        if (rows[i][0] == data.id) {
          foundIndex = i + 1;
          break;
        }
      }
    }

    var rowData = [
      data.id, data.timestamp, data.bulan, data.noPenugasan,
      data.ulp, data.petugas1, data.petugas2, data.penyulang,
      data.keypoint, data.titikStart, data.titikFinish,
      JSON.stringify(data.photos)
    ];

    if (foundIndex > -1) {
      sheet.getRange(foundIndex, 1, 1, rowData.length).setValues([rowData]);
    } else {
      sheet.appendRow(rowData);
    }
    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  }
}`;

  const currentData = selectedUlp ? masterData[selectedUlp] : null;

  return (
    <div className="max-w-4xl mx-auto space-y-6">

      <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 flex flex-col gap-3">
        <div className="flex items-start gap-3">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-blue-600 mt-1 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          <div>
            <h3 className="font-bold text-blue-800">PENTING: Fitur Edit Tidak Masuk?</h3>
            <p className="text-sm text-blue-700 mt-1">
              Agar fitur <strong>EDIT</strong> bisa bekerja menimpa baris di Spreadsheet, skrip Google Anda harus mendukung fungsi pencarian ID.
            </p>
          </div>
        </div>
        <button 
          onClick={() => setShowScriptGuide(!showScriptGuide)}
          className="text-xs font-black uppercase tracking-widest bg-blue-600 text-white px-4 py-2 rounded-lg self-start hover:bg-blue-700"
        >
          {showScriptGuide ? 'Tutup Panduan' : 'Lihat Kode Google Script Terbaru'}
        </button>
      </div>

      {showScriptGuide && (
        <div className="bg-slate-900 rounded-xl p-6 text-slate-300 animate-fade-in relative">
          <h4 className="text-white font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500"></span>
            Google Apps Script Template
          </h4>
          <pre className="text-[10px] font-mono bg-black/50 p-4 rounded-lg overflow-x-auto border border-white/10 select-all">
            {gasCode}
          </pre>
          <p className="text-[10px] mt-4 text-slate-400">
            * Salin kode di atas ke editor Google Script Anda, Simpan, dan Lakukan <strong>Deploy Ulang (New Deployment)</strong>.
          </p>
        </div>
      )}

      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h2 className="text-xl font-bold text-slate-800">Kelola Data Master</h2>
            <p className="text-slate-500">Edit daftar Petugas & Penyulang per ULP</p>
          </div>
          {onInitDefault && (
             <button 
              onClick={() => {
                if(window.confirm("Ini akan menimpa data di Spreadsheet dengan Data Default Aplikasi. Lanjutkan?")) {
                  onInitDefault();
                }
              }}
              className="text-xs bg-slate-100 hover:bg-slate-200 text-slate-600 px-3 py-2 rounded border border-slate-300 transition-colors"
             >
               Inisialisasi Database
             </button>
          )}
        </div>

        <div className="mb-6">
          <label className="block text-sm font-medium text-slate-700 mb-1">Pilih ULP</label>
          <select
            className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent bg-white"
            value={selectedUlp}
            onChange={(e) => setSelectedUlp(e.target.value as ULPName)}
          >
            <option value="">-- Pilih Unit Layanan Pelanggan --</option>
            {Object.values(masterData).map((data: ULPData) => (
              <option key={data.name} value={data.name}>
                {data.name}
              </option>
            ))}
          </select>
        </div>

        {selectedUlp && currentData && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-fade-in">
            {/* Manage Petugas */}
            <div className="space-y-4">
              <div className="bg-cyan-50 p-4 rounded-lg border border-cyan-100">
                <h3 className="font-semibold text-cyan-800 mb-2">Tambah Petugas</h3>
                <form onSubmit={handleAddPetugasSubmit} className="flex flex-col gap-2">
