import { ReportData, ULPData } from '../types';

/**
 * ⚠️ PENTING: Jika muncul "Failed to fetch", penyebabnya adalah:
 * 1. URL Script salah atau sudah tidak aktif.
 * 2. Script TIDAK di-deploy sebagai "Anyone" (Siapa Saja, bahkan tanpa login Google).
 * 3. Browser memblokir karena masalah CORS (Script Google harus mengembalikan response yang benar).
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbyxQLvmw8ci2BIe4xzbL3dC3BldsC3AbWzhrVrolS-1d7LU-Edj5fmlFqyPJx68Yz95/exec'; 

export const api = {
  getAllData: async () => {
    try {
      // Menggunakan fetch standar untuk GET. 
      // GAS akan melakukan redirect, pastikan browser mengikuti redirect tersebut.
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        headers: { 
          'Accept': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`Server merespon dengan status: ${response.status}`);
      }

      const text = await response.text();

      // Jika response diawali '<', berarti GAS mengembalikan halaman login/error HTML
      if (text.trim().startsWith('<')) {
        throw new Error("Izin Ditolak: Pastikan Google Script di-deploy sebagai 'Anyone' (Bukan 'User accessing the web app').");
      }

      return JSON.parse(text);
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      throw new Error(error.message || "Koneksi ke Database Gagal.");
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const payload = {
        action: isEdit ? 'updateReport' : 'saveReport',
        data: report
      };

      /**
       * PENTING: Mengirim JSON sebagai 'text/plain' adalah trik terbaik untuk Google Apps Script
       * karena menghindari 'CORS Preflight (OPTIONS request)' yang sering gagal di GAS.
       */
      const response = await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors', // 'no-cors' menjamin request terkirim, meski kita tidak bisa membaca response suksesnya
        headers: { 
          'Content-Type': 'text/plain' 
        },
        body: JSON.stringify(payload)
      });

      // Karena mode 'no-cors', response.ok akan selalu false dan status 0.
      // Kita asumsikan sukses jika tidak ada exception di network.
      return true;
    } catch (error) {
      console.error("API Error (Save/Update):", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      const payload = {
        action: 'updateMaster',
        data: masterData
      };

      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload)
      });
      return true;
    } catch (error) {
      console.error("API Error (UpdateMaster):", error);
      return true;
    }
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { DATA_ULP as INITIAL_DATA_ULP, APP_VERSION } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";

declare global {
  interface Window {
    ExcelJS: any;
  }
}

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [errorLoad, setErrorLoad] = useState<string | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });

  const [tableStartDate, setTableStartDate] = useState('');
  const [tableEndDate, setTableEndDate] = useState('');
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  const pendingUpdatesRef = useRef<Map<string, string>>(new Map());

  useEffect(() => {
    const savedDemo = localStorage.getItem('yandal_demo_mode');
    if (savedDemo === 'true') {
      setIsDemoMode(true);
      const savedReports = localStorage.getItem('yandal_local_reports');
      if (savedReports) setReports(JSON.parse(savedReports));
    }
    fetchData(true);
  }, []);

  useEffect(() => {
    if (view === 'TABLE' && !isDemoMode) {
      fetchData(false);
    }
  }, [tableStartDate, tableEndDate, tableUlpFilter, view]);

  const fetchData = async (showLoading = true) => {
    if (isDemoMode) return;

    if (showLoading) {
      setIsLoading(true);
      setErrorLoad(null);
    }
    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();
          prevReports.forEach(r => reportMap.set(r.id, r));

          data.reports.forEach((serverReport: ReportData) => {
            const existing = reportMap.get(serverReport.id);
            const pendingTimestamp = pendingUpdatesRef.current.get(serverReport.id);

            if (pendingTimestamp && new Date(serverReport.timestamp) < new Date(pendingTimestamp)) {
              return; 
            }

            if (!existing || new Date(serverReport.timestamp) >= new Date(existing.timestamp)) {
              reportMap.set(serverReport.id, serverReport);
            }
          });

          return Array.from(reportMap.values());
        });

        if (data.masterData) setMasterData(data.masterData);
      }
    } catch (error: any) {
      console.error("Fetch failed:", error);
      if (showLoading) {
        const msg = error.message === "Failed to fetch" 
          ? "Gagal terhubung ke Google Script. Pastikan Script sudah di-deploy sebagai 'Anyone' (Bukan internal/pribadi)."
          : error.message || "Gagal terhubung ke database.";
        setErrorLoad(msg);
      }
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const startDemoMode = () => {
    setIsDemoMode(true);
    localStorage.setItem('yandal_demo_mode', 'true');
    setErrorLoad(null);
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setShowAdminLogin(false);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setEditingReport(null);
  };

  const handleBackToMenu = () => {
     if (view === 'CONFIG') {
        setView('LOGIN');
        setRole(null);
     } else {
        if (role === UserRole.ADMIN) {
           setView('DASHBOARD');
        } else {
           setView('LOGIN');
           setRole(null);
        }
     }
     setEditingReport(null);
  };

  const handleSaveReport = async (data: ReportData) => {
    setIsSyncing(true);
    const isEditMode = !!editingReport;

    pendingUpdatesRef.current.set(data.id, data.timestamp);

    setReports(prev => {
      const filtered = prev.filter(r => r.id !== data.id);
      return [data, ...filtered];
    });

    try {
      if (isDemoMode) {
        const currentReports = [data, ...reports.filter(r => r.id !== data.id)];
        localStorage.setItem('yandal_local_reports', JSON.stringify(currentReports));
        setIsSyncing(false);
      } else {
        const success = await api.saveReport(data, isEditMode);
        if (!success) throw new Error("Gagal kirim ke server");

        // Tetap nyalakan syncing selama 6 detik untuk memastikan sheet selesai proses
        setTimeout(() => {
          fetchData(false);
          pendingUpdatesRef.current.delete(data.id);
          setIsSyncing(false);
        }, 6000);
      }

      setEditingReport(null);
      setView('TABLE');
    } catch (e) {
      alert("Gagal sinkronisasi ke Spreadsheet. Data tetap tersimpan di layar sementara, silakan refresh manual nanti.");
      setIsSyncing(false);
    }
  };

  const openEditForm = (report: ReportData) => {
    setEditingReport(report);
    setView('INPUT');
  };

  const filteredReportsForTable = useMemo(() => {
    const uniqueMap = new Map<string, ReportData>();
    const sortedRaw = [...reports].sort((a, b) => 
      new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
    );

    sortedRaw.forEach(r => uniqueMap.set(r.id, r));
    const uniqueReportsList = Array.from(uniqueMap.values());

    return uniqueReportsList
      .filter(r => {
        const sessionMatch = !session.ulp || r.ulp === session.ulp;
        if (!sessionMatch) return false;
        const adminUlpMatch = role !== UserRole.ADMIN || !tableUlpFilter || r.ulp === tableUlpFilter;
        if (!adminUlpMatch) return false;
        const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
        const startMatch = !tableStartDate || reportDate >= tableStartDate;
        const endMatch = !tableEndDate || reportDate <= tableEndDate;
        return startMatch && endMatch;
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  const fixBase64 = (str: string) => {
    if (!str || !str.includes(',')) return null;
    const [meta, data] = str.split(',');
    return meta + ',' + data.replace(/\s/g, '+');
  };

  const formatDriveUrl = (url: string) => {
    if (url.includes('drive.google.com/file/d/')) {
      const id = url.split('/d/')[1]?.split('/')[0];
      if (id) return `https://lh3.googleusercontent.com/d/${id}`;
    }
    return url;
  };

  const getBase64FromUrl = async (url: string): Promise<string | null> => {
    if (!url) return null;
    if (url.startsWith('data:image')) return fixBase64(url);
    try {
      const formattedUrl = formatDriveUrl(url);
      const response = await fetch(formattedUrl);
      if (!response.ok) return null;
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = () => resolve(null);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.error("Failed to fetch image", e);
      return null;
    }
  };

  const ensureExcelJS = (): Promise<any> => {
    return new Promise((resolve, reject) => {
      const existing = window.ExcelJS || (window as any).Excel;
      if (existing) {
        resolve(existing);
        return;
      }
      const script = document.createElement('script');
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/exceljs/4.4.0/exceljs.min.js';
      script.onload = () => resolve(window.ExcelJS || (window as any).Excel);
      script.onerror = () => reject(new Error("Gagal memuat library ExcelJS"));
      document.head.appendChild(script);
    });
  };

  const handleDownloadExcel = async () => {
    let ExcelJS;
    try {
      ExcelJS = await ensureExcelJS();
    } catch (err) {
      alert("Library ExcelJS tidak dapat dimuat.");
      return;
    }

    setIsSyncing(true);

    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet('Laporan Patrol');

    const columns: any[] = [
      { header: 'No', key: 'no', width: 5 },
      { header: 'Tanggal', key: 'tanggal', width: 15 },
      { header: 'No. Penugasan', key: 'noPenugasan', width: 25 },
      { header: 'ULP', key: 'ulp', width: 20 },
      { header: 'Petugas 1', key: 'petugas1', width: 20 },
      { header: 'Petugas 2', key: 'petugas2', width: 20 },
      { header: 'Penyulang', key: 'penyulang', width: 15 },
      { header: 'Keypoint', key: 'keypoint', width: 25 },
      { header: 'Start', key: 'start', width: 25 },
      { header: 'Finish', key: 'finish', width: 25 },
    ];

    for (let i = 1; i <= 6; i++) {
      columns.push({ header: `Foto Sebelum ${i}`, key: `sebelum_${i}`, width: 35 });
      columns.push({ header: `Foto Sesudah ${i}`, key: `sesudah_${i}`, width: 35 });
    }

    worksheet.columns = columns;
    worksheet.getRow(1).font = { bold: true };
    worksheet.getRow(1).alignment = { vertical: 'middle', horizontal: 'center' };
    worksheet.getRow(1).height = 25;

    for (const [index, r] of filteredReportsForTable.entries()) {
      const row = worksheet.addRow({
        no: index + 1,
        tanggal: new Date(r.timestamp).toLocaleDateString('id-ID'),
        noPenugasan: r.noPenugasan,
        ulp: r.ulp,
        petugas1: r.petugas1,
        petugas2: r.petugas2,
        penyulang: r.penyulang,
        keypoint: r.keypoint,
        start: r.titikStart,
        finish: r.titikFinish,
      });

      row.height = 110; 
      row.alignment = { vertical: 'middle', horizontal: 'center' };

      for (let s = 0; s < 6; s++) {
        const fotoSebelumUrl = r.photos?.sebelum?.[s];
        const fotoSesudahUrl = r.photos?.sesudah?.[s];
        const colSebelum = 10 + s * 2;
        const colSesudah = 11 + s * 2;

        if (fotoSebelumUrl) {
          try {
            const base64 = await getBase64FromUrl(fotoSebelumUrl);
            if (base64) {
              const imgId = workbook.addImage({ 
                base64, 
                extension: base64.startsWith('data:image/png') ? 'png' : 'jpeg' 
              });
              worksheet.addImage(imgId, {
                tl: { col: colSebelum, row: row.number - 1 },
                ext: { width: 220, height: 130 }
              });
            }
          } catch (e) {}
        }

        if (fotoSesudahUrl) {
          try {
            const base64 = await getBase64FromUrl(fotoSesudahUrl);
            if (base64) {
              const imgId = workbook.addImage({ 
                base64, 
                extension: base64.startsWith('data:image/png') ? 'png' : 'jpeg' 
              });
              worksheet.addImage(imgId, {
                tl: { col: colSesudah, row: row.number - 1 },
                ext: { width: 220, height: 130 }
              });
            }
          } catch (e) {}
        }
      }
    }

    const dateStr = new Date().toISOString().split('T')[0];
    const filename = `Laporan_Patrol_${tableUlpFilter || 'Semua_ULP'}_${dateStr}.xlsx`;

    try {
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], {
        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      alert("Terjadi kesalahan saat mengolah file Excel.");
    } finally {
      setIsSyncing(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4 p-4 text-center">
