import { ReportData, ULPData } from '../types';

/**
 * ⚠️ SOLUSI ERROR "Failed to fetch":
 * 1. URL SCRIPT: Ganti URL di bawah dengan "Web App URL" asli dari Google Apps Script Anda.
 * 2. IZIN AKSES: Saat Deploy, pastikan "Who has access" disetel ke "Anyone".
 * 3. DEPLOY ULANG: Jika Anda mengubah kode di GAS, Anda WAJIB melakukan "New Deployment".
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbyxQLvmw8ci2BIe4xzbL3dC3BldsC3AbWzhrVrolS-1d7LU-Edj5fmlFqyPJx68Yz95/exec'; 

export const api = {
  getAllData: async () => {
    try {
      // Kita gunakan request GET paling sederhana tanpa header kustom
      // untuk meminimalisir kemungkinan blokir CORS oleh browser.
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`);

      if (!response.ok) {
        throw new Error(`Server Error: ${response.status}`);
      }

      const text = await response.text();

      // Jika response diawali '<', berarti Google mengembalikan halaman Login (karena izin bukan 'Anyone')
      if (text.trim().startsWith('<')) {
        throw new Error("Izin Akses Ditolak. Pastikan Script di-deploy dengan setting 'Who has access: Anyone'.");
      }

      try {
        return JSON.parse(text);
      } catch (e) {
        console.error("JSON Parse Error. Server response:", text);
        throw new Error("Data yang diterima dari server tidak valid (Bukan JSON).");
      }
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      // Pesan error yang lebih deskriptif untuk user
      if (error.message === 'Failed to fetch') {
        throw new Error("Gagal terhubung ke Google. Periksa URL Script di file api.ts dan pastikan sudah di-deploy sebagai 'Anyone'.");
      }
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const payload = {
        action: isEdit ? 'updateReport' : 'saveReport',
        data: report
      };

      // Menggunakan 'no-cors' adalah cara paling aman untuk mengirim data ke GAS
      // karena GAS seringkali tidak mengirimkan header CORS yang tepat pada request POST.
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors', 
        headers: { 
          'Content-Type': 'text/plain' 
        },
        body: JSON.stringify(payload)
      });

      return true;
    } catch (error) {
      console.error("API Error (Save/Update):", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      const payload = {
        action: 'updateMaster',
        data: masterData
      };

      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload)
      });
      return true;
    } catch (error) {
      console.error("API Error (UpdateMaster):", error);
      return true;
    }
  }
};

