function doGet(e) {
  try {
    var action = e.parameter.action;
    if (action === 'getAll') {
      var ss = SpreadsheetApp.getActiveSpreadsheet();
      var sheet = ss.getSheetByName('Laporan');
      if (!sheet) {
        return ContentService.createTextOutput(JSON.stringify({reports: [], error: "Sheet Laporan tidak ditemukan"}))
          .setMimeType(ContentService.MimeType.JSON);
      }
      var data = sheet.getDataRange().getValues();
      var reports = [];
      // Mulai dari baris 2 (index 1) untuk melewati header
      for (var i = 1; i < data.length; i++) {
        if (!data[i][0]) continue; // Lewati jika ID kosong
        reports.push({
          id: data[i][0].toString(),
          timestamp: data[i][1],
          bulan: data[i][2],
          noPenugasan: data[i][3],
          ulp: data[i][4],
          petugas1: data[i][5],
          petugas2: data[i][6],
          penyulang: data[i][7],
          keypoint: data[i][8],
          titikStart: data[i][9],
          titikFinish: data[i][10],
          photos: JSON.parse(data[i][11] || '{"sebelum":[],"sesudah":[]}')
        });
      }
      return ContentService.createTextOutput(JSON.stringify({reports: reports}))
        .setMimeType(ContentService.MimeType.JSON);
    }
  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({error: err.message}))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  try {
    var request = JSON.parse(e.postData.contents);
    var action = request.action;
    var data = request.data;
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = ss.getSheetByName('Laporan');

    if (!sheet) {
       // Buat sheet jika belum ada (opsional)
       sheet = ss.insertSheet('Laporan');
       sheet.appendRow(["ID", "Timestamp", "Bulan", "No Penugasan", "ULP", "Petugas 1", "Petugas 2", "Penyulang", "Keypoint", "Start", "Finish", "Photos"]);
    }

    if (action === 'saveReport' || action === 'updateReport') {
      var rows = sheet.getDataRange().getValues();
      var foundIndex = -1;

      if (action === 'updateReport') {
        for (var i = 1; i < rows.length; i++) {
          if (rows[i][0] == data.id) {
            foundIndex = i + 1;
            break;
          }
        }
      }

      var rowData = [
        data.id, data.timestamp, data.bulan, data.noPenugasan,
        data.ulp, data.petugas1, data.petugas2, data.penyulang,
        data.keypoint, data.titikStart, data.titikFinish,
        JSON.stringify(data.photos)
      ];

      if (foundIndex > -1) {
        sheet.getRange(foundIndex, 1, 1, rowData.length).setValues([rowData]);
      } else {
        sheet.appendRow(rowData);
      }
    }
    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}`;

