import { ReportData, ULPData } from '../types';

// URL Default (Fallback jika belum diatur di menu Admin)
const DEFAULT_URL = 'https://script.google.com/macros/s/AKfycbyxQLvmw8ci2BIe4xzbL3dC3BldsC3AbWzhrVrolS-1d7LU-Edj5fmlFqyPJx68Yz95/exec';

const getBaseUrl = () => {
  return localStorage.getItem('yandal_gas_url') || DEFAULT_URL;
};

export const api = {
  // Fungsi untuk mengecek validitas URL
  testConnection: async (url: string) => {
    try {
      const response = await fetch(`${url}?action=getAll`, { method: 'GET' });
      return response.ok;
    } catch (e) {
      return false;
    }
  },

  getAllData: async () => {
    const url = getBaseUrl();
    try {
      // Menggunakan request GET paling murni tanpa kustom header untuk menghindari CORS preflight
      const response = await fetch(`${url}?action=getAll`);

      if (!response.ok) {
        throw new Error(`Status: ${response.status}`);
      }

      const text = await response.text();

      if (text.trim().startsWith('<')) {
        throw new Error("Izin Ditolak: Script belum disetel ke 'Anyone' atau Anda sedang login ke banyak akun Google.");
      }

      return JSON.parse(text);
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      if (error.message === 'Failed to fetch') {
        throw new Error("Koneksi diblokir browser. Pastikan URL Script benar dan di-deploy sebagai 'Anyone'.");
      }
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    const url = getBaseUrl();
    try {
      const payload = {
        action: isEdit ? 'updateReport' : 'saveReport',
        data: report
      };

      // POST ke GAS paling aman menggunakan mode 'no-cors' dan Content-Type text/plain
      await fetch(url, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload)
      });

      return true;
    } catch (error) {
      console.error("API Error (Save):", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    const url = getBaseUrl();
    try {
      const payload = {
        action: 'updateMaster',
        data: masterData
      };

      await fetch(url, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload)
      });
      return true;
    } catch (error) {
      console.error("API Error (UpdateMaster):", error);
      return true;
    }
  }
};

import React, { useState, useEffect } from 'react';
import { ULPName, ULPData } from '../types';
import { api } from '../services/api';

interface AdminSettingsProps {
  masterData: Record<string, ULPData>;
  onAddPetugas: (ulp: ULPName, names: string[]) => void;
  onDeletePetugas: (ulp: ULPName, name: string) => void;
  onAddPenyulang: (ulp: ULPName, names: string[]) => void;
  onDeletePenyulang: (ulp: ULPName, name: string) => void;
  onInitDefault?: () => void;
}

export const AdminSettings: React.FC<AdminSettingsProps> = ({ 
  masterData, 
  onAddPetugas, 
  onDeletePetugas, 
  onAddPenyulang,
  onDeletePenyulang,
  onInitDefault
}) => {
  const [selectedUlp, setSelectedUlp] = useState<ULPName | ''>('');
  const [newPetugas, setNewPetugas] = useState('');
  const [newPenyulang, setNewPenyulang] = useState('');
  const [showScriptGuide, setShowScriptGuide] = useState(false);

  // Database URL Settings
  const [gasUrl, setGasUrl] = useState('');
  const [isTesting, setIsTesting] = useState(false);
  const [testResult, setTestResult] = useState<{success: boolean, message: string} | null>(null);

  useEffect(() => {
    const savedUrl = localStorage.getItem('yandal_gas_url') || '';
    setGasUrl(savedUrl);
  }, []);

  const handleSaveUrl = async () => {
    setIsTesting(true);
    setTestResult(null);

    if (!gasUrl.startsWith('https://script.google.com')) {
      setTestResult({ success: false, message: 'URL tidak valid. Harus diawali script.google.com' });
      setIsTesting(false);
      return;
    }

    const isOk = await api.testConnection(gasUrl);
    if (isOk) {
      localStorage.setItem('yandal_gas_url', gasUrl);
      setTestResult({ success: true, message: 'Koneksi Berhasil! URL telah disimpan.' });
      setTimeout(() => window.location.reload(), 1500);
    } else {
      setTestResult({ success: false, message: 'Gagal Terhubung. Pastikan Deployment "Anyone" aktif.' });
    }
    setIsTesting(false);
  };

  const handleAddPetugasSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedUlp && newPetugas.trim()) {
      const names = newPetugas.split(/[\n,]+/).map(s => s.trim()).filter(Boolean);
      if (names.length > 0) {
        onAddPetugas(selectedUlp, names);
        setNewPetugas('');
      }
    }
  };

  const handleAddPenyulangSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedUlp && newPenyulang.trim()) {
